// Definiere eine Klasse für die Individuen
class Individual {
public:
    vector<int> genes;
    double fitness;

    Individual(vector<int> genes) : genes(genes), fitness(0) {}

    // Fitness-Funktion (z.B. Summe der Elemente, je kleiner desto besser)
    void evaluateFitness() {
        fitness = 0;
        for (int gene : genes) {
            fitness += abs(gene);
        }
    }

    // Kreuzung (zufällige Teilung und Kombination)
    Individual crossover(Individual other) {
        int crossoverPoint = rand() % genes.size();
        vector<int> newGenes(genes.size());
        for (int i = 0; i < crossoverPoint; i++) {
            newGenes[i] = genes[i];
        }
        for (int i = crossoverPoint; i < genes.size(); i++) {
            newGenes[i] = other.genes[i];
        }
        return Individual(newGenes);
    }

    // Mutation (zufällige Änderung eines Genes)
    void mutate(double mutationRate) {
        for (int i = 0; i < genes.size(); i++) {
            if (rand() / (double)RAND_MAX < mutationRate) {
                genes[i] = rand() % 100; // Zufälliger Wert zwischen 0 und 99
            }
        }
    }
};

